import React, { useState } from "react";
import { Link } from "react-router-dom";
import Navbar from "../components/Navbar";

const modules = [
  {
    icon: "📊",
    title: "Tiered Tariff Billing",
    desc: "Configurable rate bands per apartment turn metered kL readings into accurate, transparent charges.",
  },
  {
    icon: "⚖️",
    title: "Fair Cost Apportionment",
    desc: "Shared costs — tankers, municipal supply, garden, lobby — split by consumption, with a flat-area fallback for meter-less flats.",
  },
  {
    icon: "🔎",
    title: "Leak & Overuse Alerts",
    desc: "A 2-sigma statistical check plus threshold rules catch abnormal spikes and email residents before the bill does.",
  },
  {
    icon: "🧾",
    title: "PDF Invoices & Email",
    desc: "Every billing cycle generates a downloadable invoice per household and sends automated email notifications.",
  },
];

const CONTACT_TOPICS = ["Billing question", "Technical issue", "New apartment onboarding", "Something else"];

export default function LandingPage() {
  const year = new Date().getFullYear();

  const [form, setForm] = useState({ name: "", email: "", topic: CONTACT_TOPICS[0], message: "" });
  const [status, setStatus] = useState("idle");

  const update = (field) => (e) => setForm({ ...form, [field]: e.target.value });

  const submitQuery = (e) => {
    e.preventDefault();
    if (!form.name.trim() || !form.email.trim() || !form.message.trim()) {
      setStatus("error");
      return;
    }
    setStatus("sending");
    setTimeout(() => {
      setStatus("sent");
      setForm({ name: "", email: "", topic: CONTACT_TOPICS[0], message: "" });
    }, 700);
  };

  return (
    <div style={{ background: "#f8fafc", minHeight: "100vh", fontFamily: "system-ui, sans-serif" }}>
      <Navbar />

      {/* HERO SECTION */}
      <section style={{
        position: "relative",
        background: "linear-gradient(135deg, #0f172a 0%, #083344 50%, #022c22 100%)",
        color: "#ffffff",
        padding: "100px 0 140px 0",
        overflow: "hidden"
      }}>
        {/* Abstract structural graphic elements */}
        <div style={{
          position: "absolute", right: "-10%", top: "-10%", width: "600px", height: "600px",
          background: "radial-gradient(circle, rgba(14,116,144,0.15) 0%, transparent 70%)", pointerEvents: "none"
        }} />
        <div style={{
          position: "absolute", left: "-5%", bottom: "10%", width: "400px", height: "400px",
          background: "radial-gradient(circle, rgba(20,184,166,0.1) 0%, transparent 70%)", pointerEvents: "none"
        }} />

        <div className="container" style={{ maxWidth: "1100px", margin: "0 auto", padding: "0 24px", position: "relative", zIndex: 2 }}>
          <span style={{
            display: "inline-block", background: "rgba(20,184,166,0.15)", color: "#2dd4bf",
            padding: "6px 16px", borderRadius: "999px", fontSize: "14px", fontWeight: "600", marginBottom: "24px",
            border: "1px solid rgba(20,184,166,0.3)"
          }}>
            💧 For apartment communities
          </span>

          <h1 style={{ fontSize: "clamp(2.5rem, 5vw, 4.2rem)", fontWeight: "800", lineHeight: "1.15", letterSpacing: "-0.02em", marginBottom: "24px" }}>
            Every litre, <span style={{ background: "linear-gradient(to right, #38bdf8, #2dd4bf)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>accounted for.</span>
          </h1>

          <p style={{ fontSize: "clamp(1.1rem, 2vw, 1.25rem)", color: "#cbd5e1", maxWidth: "700px", lineHeight: "1.6", marginBottom: "40px" }}>
            AquaTrack meters household consumption, apportions bulk water purchases fairly,
            and flags leaks before they become expensive — with a beautifully integrated resident dashboard and
            a clean, automated admin billing ecosystem.
          </p>

          <div style={{ display: "flex", gap: 16, flexWrap: "wrap", marginBottom: "64px" }}>
            <Link to="/register" style={{
              background: "linear-gradient(135deg, #06b6d4 0%, #0d9488 100%)", color: "#fff",
              padding: "14px 32px", borderRadius: "12px", fontWeight: "600", textDecoration: "none",
              boxShadow: "0 4px 20px rgba(6,182,212,0.35)", transition: "transform 0.2s"
            }}>Get started</Link>
            <Link to="/login" style={{
              background: "rgba(255,255,255,0.05)", color: "#fff",
              padding: "14px 32px", borderRadius: "12px", fontWeight: "600", textDecoration: "none",
              border: "1px solid rgba(255,255,255,0.15)", backdropFilter: "blur(12px)"
            }}>I already have an account</Link>
          </div>

          {/* STATS STRIP */}
          <div style={{
            display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: "24px",
            background: "rgba(255,255,255,0.03)", padding: "32px", borderRadius: "24px",
            border: "1px solid rgba(255,255,255,0.08)", backdropFilter: "blur(8px)"
          }}>
            {[
              { val: "2σ", label: "statistical leak detection" },
              { val: "Tiered", label: "rate-band billing engine" },
              { val: "PDF", label: "invoice per household" },
              { val: "Live", label: "consumption dashboards" }
            ].map((s, idx) => (
              <div key={idx} style={{ textAlign: "center", borderRight: idx !== 3 ? "1px solid rgba(255,255,255,0.1)" : "none" }}>
                <div style={{ fontSize: "28px", fontWeight: "700", color: "#2dd4bf" }}>{s.val}</div>
                <div style={{ fontSize: "13px", color: "#94a3b8", marginTop: "4px" }}>{s.label}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Dynamic Wave SVG Base Divider */}
        <div style={{ position: "absolute", bottom: 0, left: 0, width: "100%", overflow: "hidden", lineHeight: 0 }}>
          <svg viewBox="0 0 1440 74" preserveAspectRatio="none" style={{ width: "100%", height: "40px" }}>
            <path d="M0,32 C240,70 480,10 720,40 C960,70 1200,20 1440,50 L1440,74 L0,74 Z" fill="#f8fafc" />
          </svg>
        </div>
      </section>

      {/* MODULE FEATURES */}
      <section style={{ padding: "100px 0" }}>
        <div className="container" style={{ maxWidth: "1100px", margin: "0 auto", padding: "0 24px" }}>
          <div style={{ textAlign: "center", marginBottom: "60px" }}>
            <span style={{ color: "#0d9488", fontWeight: "600", textTransform: "uppercase", letterSpacing: "0.1em", fontSize: "14px" }}>What AquaTrack handles</span>
            <h2 style={{ fontSize: "36px", fontWeight: "800", color: "#0f172a", marginTop: "8px" }}>Built for the two people who run a building</h2>
            <p style={{ color: "#475569", marginTop: "12px", fontSize: "16px" }}>The resident who wants absolute billing clarity, and the admin who needs clean programmatic control.</p>
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", gap: "24px" }}>
            {modules.map((m) => (
              <div key={m.title} style={{
                background: "#ffffff", padding: "32px", borderRadius: "20px",
                boxShadow: "0 4px 6px -1px rgba(0,0,0,0.05), 0 10px 15px -3px rgba(0,0,0,0.03)",
                border: "1px solid #f1f5f9", transition: "transform 0.2s, box-shadow 0.2s"
              }}>
                <div style={{ fontSize: "36px", marginBottom: "20px", background: "#f0fdfa", width: "60px", height: "60px", display: "flex", alignItems: "center", justifyContent: "center", borderRadius: "14px" }}>{m.icon}</div>
                <h3 style={{ fontSize: "18px", fontWeight: "700", color: "#0f172a", marginBottom: "12px" }}>{m.title}</h3>
                <p style={{ fontSize: "14px", color: "#475569", lineHeight: "1.6" }}>{m.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CENTRAL MARKETING CTA */}
      <section style={{ paddingBottom: "100px" }}>
        <div className="container" style={{ maxWidth: "1100px", margin: "0 auto", padding: "0 24px" }}>
          <div style={{
            background: "linear-gradient(135deg, #0e7490 0%, #155e75 100%)",
            borderRadius: "32px", padding: "60px", textAlign: "center", color: "#ffffff",
            boxShadow: "0 20px 40px -15px rgba(14,116,144,0.4)"
          }}>
            <h2 style={{ fontSize: "32px", fontWeight: "700", marginBottom: "16px" }}>Ready to see your water bill differently?</h2>
            <p style={{ color: "#cffafe", marginBottom: "32px", maxWidth: "600px", margin: "0 auto 32px auto", fontSize: "16px" }}>
              Residents view real-time daily metrics. Admins cycle billing processes flawlessly. Let's modernize your utility footprint.
            </p>
            <Link to="/register" style={{
              display: "inline-block", background: "#ffffff", color: "#0e7490", padding: "14px 36px",
              borderRadius: "12px", fontWeight: "600", textDecoration: "none", boxShadow: "0 4px 14px rgba(0,0,0,0.1)"
            }}>Create your account</Link>
          </div>
        </div>
      </section>

      {/* CONTACT COMPONENT */}
      <section id="contact" style={{
        background: "#0f172a", color: "#ffffff", padding: "80px 0",
        backgroundImage: "radial-gradient(circle at 80% 20%, rgba(13,148,136,0.12) 0%, transparent 50%)"
      }}>
        <div className="container" style={{ maxWidth: "1100px", margin: "0 auto", padding: "0 24px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))", gap: "64px", alignItems: "center" }}>
            <div>
              <span style={{ color: "#2dd4bf", fontWeight: "600", fontSize: "14px", textTransform: "uppercase" }}>Get in touch</span>
              <h2 style={{ fontSize: "36px", fontWeight: "800", marginTop: "8px", marginBottom: "16px" }}>Have questions or a query to raise?</h2>
              <p style={{ color: "#94a3b8", lineHeight: "1.7", marginBottom: "40px" }}>
                Whether it's an optimization calculation discrepancy, structural software issues, or you're initiating bulk onboarding protocols—send a transmission.
              </p>

              <div style={{ display: "flex", flexDirection: "column", gap: "24px" }}>
                {[
                  { icon: "✉️", label: "Email Support", val: "support@aquatrack.app" },
                  { icon: "⏱️", label: "Turnaround Time", val: "Within 1 business day" }
                ].map((item, idx) => (
                  <div key={idx} style={{ display: "flex", gap: "16px", alignItems: "center" }}>
                    <div style={{ fontSize: "24px", background: "rgba(255,255,255,0.05)", width: "50px", height: "50px", borderRadius: "12px", display: "flex", alignItems: "center", justifyContent: "center" }}>{item.icon}</div>
                    <div>
                      <div style={{ fontSize: "12px", color: "#64748b", fontWeight: "600" }}>{item.label}</div>
                      <div style={{ fontSize: "15px", color: "#f1f5f9" }}>{item.val}</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div style={{ background: "rgba(255,255,255,0.02)", padding: "40px", borderRadius: "24px", border: "1px solid rgba(255,255,255,0.05)", backdropFilter: "blur(16px)" }}>
              {status === "sent" && <div style={{ background: "rgba(20,184,166,0.1)", color: "#2dd4bf", padding: "16px", borderRadius: "12px", marginBottom: "20px", border: "1px solid rgba(20,184,166,0.2)" }}>Message delivered. We will respond directly to your mailbox.</div>}
              {status === "error" && <div style={{ background: "rgba(239,68,68,0.1)", color: "#f87171", padding: "16px", borderRadius: "12px", marginBottom: "20px", border: "1px solid rgba(239,68,68,0.2)" }}>Validation missing. Complete all dynamic fields.</div>}

              <form onSubmit={submitQuery} style={{ display: "flex", flexDirection: "column", gap: "20px" }}>
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "16px" }}>
                  <div>
                    <label style={{ display: "block", fontSize: "13px", color: "#94a3b8", marginBottom: "6px" }}>Name</label>
                    <input style={{ width: "100%", background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.1)", padding: "12px", borderRadius: "8px", color: "#fff" }} value={form.name} onChange={update("name")} placeholder="Your name" />
                  </div>
                  <div>
                    <label style={{ display: "block", fontSize: "13px", color: "#94a3b8", marginBottom: "6px" }}>Email</label>
                    <input type="email" style={{ width: "100%", background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.1)", padding: "12px", borderRadius: "8px", color: "#fff" }} value={form.email} onChange={update("email")} placeholder="name@domain.com" />
                  </div>
                </div>
                <div>
                  <label style={{ display: "block", fontSize: "13px", color: "#94a3b8", marginBottom: "6px" }}>Topic</label>
                  <select style={{ width: "100%", background: "#1e293b", border: "1px solid rgba(255,255,255,0.1)", padding: "12px", borderRadius: "8px", color: "#fff" }} value={form.topic} onChange={update("topic")}>
                    {CONTACT_TOPICS.map((t) => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>
                <div>
                  <label style={{ display: "block", fontSize: "13px", color: "#94a3b8", marginBottom: "6px" }}>Message</label>
                  <textarea rows="4" style={{ width: "100%", background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.1)", padding: "12px", borderRadius: "8px", color: "#fff" }} value={form.message} onChange={update("message")} placeholder="Enter structural context details..." />
                </div>
                <button type="submit" disabled={status === "sending"} style={{
                  background: "linear-gradient(135deg, #06b6d4 0%, #0d9488 100%)", color: "#fff",
                  padding: "14px", borderRadius: "8px", fontWeight: "600", border: "none", cursor: "pointer"
